<script setup>
import{ref}from'vue';import{onShow}from'@dcloudio/uni-app';import AppHeader from'../../components/AppHeader.vue';import BottomNav from'../../components/BottomNav.vue';import{api}from'../../api'
const profile=ref(uni.getStorageSync('merchantProfile')||{});onShow(async()=>{try{profile.value=await api.merchantProfile();uni.setStorageSync('merchantProfile',profile.value)}catch(_){}})
function logout(){uni.showModal({title:'退出登录',content:'退出后需要重新输入商家账号和密码',success:async res=>{if(res.confirm){try{await api.merchantLogout()}catch(_){}uni.removeStorageSync('merchantToken');uni.removeStorageSync('merchantProfile');uni.reLaunch({url:'/pages/merchant/login'})}}})}
</script>
<template><view class="page page-with-nav"><view class="hero"><AppHeader title="我的"/><view class="profile"><view class="avatar">{{profile.merchantName?.slice(0,1)||'商'}}</view><view><text class="name">{{profile.merchantName||'商家管理员'}}</text><text class="muted">{{profile.username}} · {{profile.role}}</text></view></view></view><view class="content"><view class="card menu"><view @tap="uni.navigateTo({url:'/pages/merchant/settings'})"><text>⚙</text><text>店铺设置</text><text>›</text></view><view @tap="uni.navigateTo({url:'/pages/merchant/password'})"><text>♢</text><text>修改密码</text><text>›</text></view><view @tap="uni.reLaunch({url:'/pages/home/index'})"><text>⌂</text><text>返回用户端</text><text>›</text></view></view><button class="logout" @tap="logout">退出登录</button></view><BottomNav active="profile" merchant/></view></template>
<style scoped>.hero{padding-bottom:34rpx;background:linear-gradient(160deg,#fff2e8,#fff)}.profile{display:flex;align-items:center;gap:24rpx;margin:20rpx 30rpx;padding:30rpx;border-radius:24rpx;background:#fff}.avatar{width:104rpx;height:104rpx;border-radius:50%;background:#ff8a34;color:#fff;text-align:center;line-height:104rpx;font-size:43rpx;font-weight:800}.profile>view:last-child{display:flex;flex-direction:column;gap:10rpx}.name{font-size:34rpx;font-weight:800}.menu{padding:0 28rpx}.menu view{height:104rpx;display:flex;align-items:center;gap:22rpx;border-bottom:2rpx solid #f2f2f2}.menu view:last-child{border:0}.menu view text:nth-child(2){flex:1}.menu view text:last-child{color:#aaa;font-size:40rpx}.logout{margin-top:30rpx;height:84rpx;border-radius:42rpx;background:#fff;color:#ff4d4f;font-size:27rpx;line-height:84rpx}</style>
